This realization of CVE-2024-3183 targeting abuse of TGT (not TGS).
1. We need to get valid TGT response with ticket, encrypted by targeting principal's secret;
2. We need to get salt for target principal, which hash we want crack;
3. Combine of salt + encrypted ticket will get possibility for brute-force attach.

Realm           ::= KerberosString

PrincipalName   ::= SEQUENCE {
       name-type       [0] Int32,
       name-string     [1] SEQUENCE OF KerberosString
}

HostAddress     ::= SEQUENCE  {
    addr-type       [0] Int32,
    address         [1] OCTET STRING
}

EncryptedData   ::= SEQUENCE {
       etype   [0] Int32 -- EncryptionType --,
       kvno    [1] UInt32 OPTIONAL,
       cipher  [2] OCTET STRING -- ciphertext
}

Ticket          ::= [APPLICATION 1] SEQUENCE {
       tkt-vno         [0] INTEGER (5),
       realm           [1] Realm,
       sname           [2] PrincipalName,
       enc-part        [3] EncryptedData -- EncTicketPart
}

PA-DATA         ::= SEQUENCE {
    -- NOTE: first tag is [1], not [0]
    padata-type     [1] Int32,
    padata-value    [2] OCTET STRING -- might be encoded AP-REQ
}

EncryptionKey   ::= SEQUENCE {
       keytype         [0] Int32 -- actually encryption type --,
       keyvalue        [1] OCTET STRING
}

AuthorizationData       ::= SEQUENCE OF SEQUENCE {
    ad-type         [0] Int32,
    ad-data         [1] OCTET STRING
}

Checksum        ::= SEQUENCE {
    cksumtype       [0] Int32,
    checksum        [1] OCTET STRING
}

LastReq         ::=     SEQUENCE OF SEQUENCE {
       lr-type         [0] Int32,
       lr-value        [1] KerberosTime
}

ETYPE-INFO-ENTRY        ::= SEQUENCE {
    etype           [0] Int32,
    salt            [1] OCTET STRING OPTIONAL
}

ETYPE-INFO2-ENTRY       ::= SEQUENCE {
    etype           [0] Int32,
    salt            [1] KerberosString OPTIONAL,
    s2kparams       [2] OCTET STRING OPTIONAL
}

PA-ENC-TS-ENC           ::= SEQUENCE {
    patimestamp     [0] KerberosTime -- client's time --,
    pausec          [1] Microseconds OPTIONAL
}

KrbSalt ::= SEQUENCE {
    type      [0] Int32,
    salt      [1] OCTET STRING OPTIONAL
}

KrbKey ::= SEQUENCE {
    salt      [0] KrbSalt OPTIONAL,
    key       [1] EncryptionKey,
    s2kparams [2] OCTET STRING OPTIONAL,
    ...
}

MasterKey ::= SEQUENCE {
    keytype         [0] Int32,
    keyvalue        [1] OCTET STRING
}

KrbMKey ::= SEQUENCE {
    kvno    [0] UInt32,
    key     [1] MasterKey
}

-- encoded Transited field
TransitedEncoding       ::= SEQUENCE {
    tr-type         [0] Int32 -- must be registered --,
    contents        [1] OCTET STRING
}

KRB-CRED        ::= [APPLICATION 22] SEQUENCE {
       pvno            [0] INTEGER (5),
       msg-type        [1] INTEGER (22),
       tickets         [2] SEQUENCE OF Ticket,
       enc-part        [3] EncryptedData -- EncKrbCredPart
}

SPAKESecondFactor ::= SEQUENCE {
   type        [0] Int32,
   data        [1] OCTET STRING OPTIONAL
}

SPAKEChallenge ::= SEQUENCE {
   group       [0] Int32,
   pubkey      [1] OCTET STRING,
   factors     [2] SEQUENCE (SIZE(1..MAX)) OF SPAKESecondFactor,
}

SPAKEResponse ::= SEQUENCE {
pubkey      [0] OCTET STRING,
factor      [1] EncryptedData, -- SPAKESecondFactor
...
}
